var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_RED","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"MORIARTY_SWANSONG_NPC_QM","text":{"KOREA":"마침 연락이 왔네.","JPN":"ちょうど今、連絡が来た。","ENG":"Oh, good timing. I got a call.","TWN":"正好有消息傳來。"},"stage":{"bg":"COUNTERSIDE_RED","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"어떻게 됐지? 스완은 찾았나?","JPN":"どうなった？　スワンは見つかったか？","ENG":"What's going on? Did you find Swan?","TWN":"怎麼樣？找到史旺了嗎？"},"stage":{"bg":"COUNTERSIDE_RED","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"역시… 관리국이 보낸 요원이었군요.","JPN":"やはり……管理局のエージェントだったのですね。","ENG":"So he was an agent sent by the Administration... just as I thought.","TWN":"果然……是管理局派的人。"},"stage":{"bg":"COUNTERSIDE_RED","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"관리국 시니어 르네. 당신에게 인사드리는 건 이번이 처음이겠네요.","JPN":"管理局シニア、ルネ。あなた方にご挨拶するのはこれが初めてになりますね。","ENG":"Renée, Senior of the Administration. I guess this is the first time we're talking.","TWN":"管理局Senior芮妮。這是我第一次向你問好。"},"stage":{"bg":"COUNTERSIDE_RED","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"네가 왜 그 통신기를 가지고 있지? 스완?","JPN":"どうしてあなたが通信機を持っているんだ？　スワン。","ENG":"How come you have that comms device, Swan?","TWN":"你為什麼會有那個通訊器？史旺？"},"stage":{"bg":"COUNTERSIDE_RED","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그런 뻔한 질문을 설명하려고 연락을 드린 건 아닙니다.","JPN":"そのような質問に答えるために連絡したのではありません。","ENG":"I didn't call you just to answer such an obvious question.","TWN":"我聯繫你並不是為了回答這麼簡單的問題。"},"stage":{"bg":"COUNTERSIDE_RED","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"전 당신에게 도발이 아닌, 경고를 하고 싶은 거니까요.","JPN":"私はあなたに挑発ではなく、警告をしたいのです。","ENG":"I don't mean to provoke you. I mean to warn you.","TWN":"我想給你們一個警告，而不是挑釁。"},"stage":{"bg":"COUNTERSIDE_RED","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"네가 나한테 경고를 한다고?","JPN":"あなたが、私に？","ENG":"\\"You\\" want to warn \\"me?\\"","TWN":"警告我？"},"stage":{"bg":"COUNTERSIDE_RED","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"시니어의 죽음은 경고일 뿐이에요.","JPN":"シニアの死はただの警告です。","ENG":"The Senior's death was merely a warning.","TWN":"Senior的死只是一個警告。"},"stage":{"bg":"COUNTERSIDE_RED","slots":{"L":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"더 이상 절 쫓으려 한다면 그땐 당신도 무사하지 못할 겁니다.","JPN":"これ以上私を追うつもりなら、その時はあなたも無事では済みませんよ。","ENG":"You'll meet a similar fate if you keep coming after me.","TWN":"如果你再追我，連你自己也會陷入危險。"},"stage":{"bg":"COUNTERSIDE_RED","slots":{"L":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"사진을 퍼트린 게 너였군.","JPN":"写真をばら撒いたのはあなただったのだな。","ENG":"So it was you who spread the photo.","TWN":"原來就是你散播照片的。"},"stage":{"bg":"COUNTERSIDE_RED","slots":{"L":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"왜 이런 짓을 벌이는 거지? 지금껏 쌓아온 부와 명성을 전부 버릴 정도로 너에게 필요한 게 있나?","JPN":"なぜこんなことを？　今まで積み重ねてきた富と名声を捨てるほど、必要なものがあるのか？","ENG":"Why are you doing this? What's so important to you that you're willing to throw away all the wealth and fame you've achieved?","TWN":"你為什麼要這麼做？ 你是不是迫切需要什麼東西，以至於不惜拋棄一直以來累積的財富和名聲？"},"stage":{"bg":"COUNTERSIDE_RED","slots":{"L":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"당신도 알지 않나요? 샤레이드에서 부와 명성이란 건 쓰다 버릴 수단일 뿐이란 걸.","JPN":"あなたもわかっているのでは？　シャレードで富と名声というのは、利用して捨てる手段でしかないのです。","ENG":"I'm sure you're aware that wealth and fame are just a means to an end.","TWN":"你知道的，不是嗎？在查雷德，財富和名聲只不過是達到目的的手段。"},"stage":{"bg":"COUNTERSIDE_RED","slots":{"L":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L21_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"그 대가로 얻고 싶은 게 고작 샤레이드가 혼란에 빠지는 꼴은 아니겠지?","JPN":"その対価で得たいものが、たかがシャレードの混乱だと言うのではあるまいな？","ENG":"And I doubt you're using them just to bring chaos to Charade.","TWN":"以那麼多財富和名聲為代價得到的只是讓查雷德陷入混亂？"},"stage":{"bg":"COUNTERSIDE_RED","slots":{"L":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L22_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"세피로트 나무.","JPN":"セフィロト。","ENG":"The Tree of Sephiroth.","TWN":"生命樹。"},"stage":{"bg":"COUNTERSIDE_RED","slots":{"L":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"옆에서 듣고 계신 분도 있을 테니, 힌트는 그 정도면 충분하겠죠.","JPN":"隣で聞いている方もいらっしゃるでしょうから、ヒントはこれで十分でしょう。","ENG":"That should be enough of a clue, considering the presence of the person listening next to you.","TWN":"這個提示應該足夠了吧？相信你們旁邊也有人在聽。"},"stage":{"bg":"COUNTERSIDE_RED","slots":{"L":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"네가 그걸 어떻게…?","JPN":"どうしてあなたがそれを……？","ENG":"How did you...?","TWN":"你怎麼會知道？"},"stage":{"bg":"COUNTERSIDE_RED","slots":{"L":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"모든 건 저의 각본대로 움직일 뿐입니다, 르네.","JPN":"すべては私の脚本通りに動くのです、ルネ。","ENG":"Everything is according to my script, Renée.","TWN":"一切都在按照我的劇本進行，芮妮。"},"stage":{"bg":"SKY_NIGHT","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"당신은 각본의 수많은 엑스트라들 중 하나지만…","JPN":"あなたは脚本の中、数多くのエキストラの一人にすぎませんが……","ENG":"You are one of many background characters of the script, but...","TWN":"你是劇本中眾多的臨時演員之一，但……"},"stage":{"bg":"SKY_NIGHT","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그 사람은 이 무대를 처음부터 끝까지 지켜보는 관중이 되어야 하거든요.","JPN":"あの人にはこの舞台を最後まで見届ける観客になってもらわないと困るのですよ。","ENG":"He has to be a part of the audience and watch this performance from start to finish.","TWN":"那個人要擔任的是從頭到尾觀賞這個舞台表演的觀眾。"},"stage":{"bg":"SKY_NIGHT","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SKY_NIGHT","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"모든 게 자기가 원하는대로 흘러갈 거라 생각하다니. 오만하군.","JPN":"すべてが自分の思い通りになると思うか。傲慢だな。","ENG":"Arrogant of you to think that everything would go according to your plan.","TWN":"你以為一切都會按你的想法發展，真是傲慢。"},"stage":{"bg":"SKY_NIGHT","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"당신도 그렇지 않나요?","JPN":"あなたもそうではありませんか？","ENG":"Aren't you the same?","TWN":"你不也是這樣嗎？"},"stage":{"bg":"SKY_NIGHT","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"세상이 만든 법칙을 거스르고, 자신이 원하는 형태로 현실을 바꾸고 있는 걸요.","JPN":"世界が作った法則に逆らい、自身の望む形へと現実を変えているのですから。","ENG":"You're defying the rules made by this world and changing reality into the form you want it to be.","TWN":"你無視世界的法則，按照自己的喜好扭曲現實。"},"stage":{"bg":"SKY_NIGHT","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"흠, 나에게 이 정도로 관심을 갖는 팬이 있을 줄은 몰랐는데.","JPN":"ほう、これほど私に興味がある熱心なファンがいるとは知らなかったな。","ENG":"Hmm. I didn't know I had a fan who was interested in me like this.","TWN":"嗯，沒想到你竟然還是我的狂熱粉絲呢"},"stage":{"bg":"SKY_NIGHT","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};